package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

class CSVParserTest {

    @Mock
    private Lexer lexerMock;

    private CSVParser csvParser;

    @BeforeEach
    void setUp() throws Exception {
        MockitoAnnotations.openMocks(this);
        // Use reflection to create a CSVParser instance with mocked lexer
        csvParser = org.mockito.internal.util.reflection.ReflectionUtils.newInstance(CSVParser.class);

        // Inject lexerMock into csvParser using reflection
        java.lang.reflect.Field lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);
        lexerField.set(csvParser, lexerMock);
    }

    @Test
    void testClose_lexerNotNull_callsLexerClose() throws IOException {
        csvParser.close();
        verify(lexerMock, times(1)).close();
    }

    @Test
    void testClose_lexerNull_noException() throws Exception {
        // Set lexer to null
        java.lang.reflect.Field lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);
        lexerField.set(csvParser, null);

        // Should not throw any exception
        assertDoesNotThrow(() -> csvParser.close());
    }
}
